"""Browser-based compatibility client for user-triggered browser flows.

stoken can be generated by the browser's JS environment when a user-initiated
login flow needs compatibility help. Low-Risk Assistance Mode blocks sensitive
automation such as outreach, bulk actions, risk-control retries, and candidate
personal-data workflows before they reach this client.

Supports two modes:
  1. CDP mode: connects to user's existing Chrome via DevTools Protocol
  2. Patchright mode (fallback): launches a headless Chromium instance
"""

import sys
import time
from pathlib import Path
from types import TracebackType
from typing import Any, cast

from patchright.sync_api import sync_playwright

from boss_agent_cli.api import endpoints
from boss_agent_cli.api.throttle import RequestThrottle
from boss_agent_cli.auth.browser import _DEFAULT_CDP_URL as CDP_DEFAULT_URL
from boss_agent_cli.auth.browser import _chromium_launch_options

HOME_URL = "https://www.zhipin.com/"


class RecruiterChatTabRequired(RuntimeError):
	"""招聘者操作（issue #217 修复路径）需要用户已打开 chat/index 页。

	不自动新开 tab：避免替用户改变官方页面状态或触发额外平台风险信号。
	友好做法是返回明确指引，让用户自己打开。
	"""

	def __init__(self) -> None:
		super().__init__(
			"recruiter chat tab not found in CDP Chrome — "
			"please open https://www.zhipin.com/web/chat/index in your "
			"Chrome (CDP-attached) and retry."
		)


class BrowserSessionRequired(RuntimeError):
	"""Raised when BOSS live access requires the user's CDP browser session."""


# 超时常量
_CDP_PROBE_TIMEOUT = 3  # 显式 --cdp-url 的 CDP 探测 HTTP 超时（秒）
_CDP_AUTO_PROBE_TIMEOUT = 1  # 默认自动探测 localhost:9222 的超时（无调试端口时快速失败，省 ~2s）
_CDP_CONNECT_TIMEOUT_MS = 5000  # CDP 端口可探测但连接/枚举上下文卡住时快速失败
_NAV_TIMEOUT_MS = 15000  # 页面导航超时（毫秒）
_FETCH_TIMEOUT_MS = 6000  # browser fetch 必须结构化失败，不能挂住整轮工作流
# zhipin 首页常驻请求多、headless 下基本进不了 networkidle；domcontentloaded 后 JS
# 环境即可发 fetch，故宽限缩到 0.8s（实测每次都会耗满，缩短直接省 ~2s/搜索）。
_HEADLESS_NETWORKIDLE_GRACE_MS = 800

# macOS / Linux / Windows Chrome user data 默认路径
_CHROME_USER_DATA_CANDIDATES = [
	Path.home() / "Library/Application Support/Google/Chrome",  # macOS
	Path.home() / ".config/google-chrome",  # Linux
	Path.home() / "AppData/Local/Google/Chrome/User Data",  # Windows
]


class BrowserSession:
	"""Persistent browser session that makes API calls via page.evaluate(fetch).

	Tries CDP connection to user's Chrome first; falls back to headless patchright.
	"""

	def __init__(
		self,
		cookies: dict[str, Any],
		user_agent: str,
		*,
		delay: tuple[float, float] = (1.5, 3.0),
		cdp_url: str | None = None,
		logger: Any = None,
		prefer_cdp: bool = False,
		require_cdp: bool = False,
	) -> None:
		self._throttle = RequestThrottle(delay)
		# patchright / BridgeClient 运行时创建；注解为 Any 让 mypy 对外部依赖放行
		self._pw: Any = None
		self._browser: Any = None
		self._context: Any = None
		self._page: Any = None
		self._cookies = cookies
		self._user_agent = user_agent
		self._started = False
		self._cdp_url = cdp_url
		self._is_cdp = False
		self._own_context = False  # 是否由我们创建的 context（需要在 close 时清理）
		self._logger = logger
		self._bridge_client: Any = None
		self._is_bridge = False
		self._prefer_cdp = prefer_cdp
		self._require_cdp = require_cdp

	def _log(self, message: str) -> None:
		"""通过注入的 logger 输出，受 --log-level 控制。"""
		if self._logger:
			self._logger.info(message)
		else:
			print(message, file=sys.stderr)

	def _ensure_started(self) -> None:
		if self._started:
			return

		if self._require_cdp:
			self._pw = sync_playwright().start()
			if self._try_cdp():
				return
			try:
				self._pw.stop()
			except Exception:
				pass
			self._pw = None
			raise BrowserSessionRequired(
				"BROWSER_SESSION_REQUIRED: start the fixed Edge/Chrome CDP window "
				"and keep a logged-in zhipin.com page open before running BOSS live commands."
			)

		if self._prefer_cdp:
			self._pw = sync_playwright().start()
			if self._try_cdp():
				return
			try:
				self._pw.stop()
			except Exception:
				pass
			self._pw = None
			if self._try_bridge():
				return
			self._pw = sync_playwright().start()
			self._start_headless()
			return

		# 优先尝试 Bridge 模式（Chrome 扩展 + daemon，零配置）
		if self._try_bridge():
			return

		self._pw = sync_playwright().start()

		# 第二优先：CDP 连接用户 Chrome（登录态兼容）
		if self._try_cdp():
			return

		# 兜底：启动 headless patchright
		self._start_headless()

	def _try_bridge(self) -> bool:
		"""尝试通过 Browser Bridge（Chrome 扩展 + daemon）连接。"""
		try:
			from boss_agent_cli.bridge.client import BridgeClient

			client = BridgeClient()
			if not client.is_running():
				return False
			if not client.is_extension_connected():
				self._log("[boss] Bridge daemon 运行中但扩展未连接")
				return False
			self._bridge_client = client
			self._started = True
			self._is_cdp = False
			self._is_bridge = True
			self._log("[boss] Bridge 模式连接成功（Chrome 扩展 + daemon）")
			return True
		except Exception:
			return False

	def _try_cdp(self) -> bool:
		"""Try connecting to user's Chrome via CDP.

		Attempts in order:
		  1. Explicit cdp_url if provided
		  2. Default http://localhost:9222 (+ auto WS fallback)
		  3. WebSocket URL from Chrome's DevToolsActivePort file
		"""
		urls_to_try = []
		if self._cdp_url:
			urls_to_try.append(self._cdp_url)
		urls_to_try.append(CDP_DEFAULT_URL)

		# 从 DevToolsActivePort 文件读取 WebSocket URL
		ws_url = self._read_devtools_active_port()
		if ws_url:
			urls_to_try.append(ws_url)

		for url in urls_to_try:
			if self._try_connect(url):
				return True
			# HTTP URL 连接失败时，尝试从 /json/version 获取 WS URL。
			# 仅对用户显式提供的 --cdp-url 用较长超时；默认 localhost:9222 自动探测
			# 用短超时快速失败（无调试端口时避免白等 ~2s）。
			if url.startswith("http"):
				probe_timeout = _CDP_PROBE_TIMEOUT if url == self._cdp_url else _CDP_AUTO_PROBE_TIMEOUT
				ws = self._fetch_ws_url(url, timeout=probe_timeout)
				if ws and self._try_connect(ws):
					return True
		return False

	def _try_connect(self, url: str) -> bool:
		"""Attempt a single CDP connection, reusing user's existing context.

		Reuses the first existing browser context to preserve the user's
		login state and avoid creating extra browser state. Only creates a
		new context when none exists.
		"""
		try:
			self._browser = self._pw.chromium.connect_over_cdp(url, timeout=_CDP_CONNECT_TIMEOUT_MS)
			contexts = self._browser.contexts

			if contexts:
				# 复用用户现有 context（保留登录态，避免额外浏览器状态）
				self._context = contexts[0]
				self._own_context = False  # 非我们创建，close 时不关闭
			else:
				# 没有已存在 context，创建新的并注入 cookies
				self._context = self._browser.new_context()
				if self._cookies:
					self._context.add_cookies(
						[
							{"name": name, "value": value, "domain": ".zhipin.com", "path": "/"}
							for name, value in self._cookies.items()
						]
					)
				self._own_context = True

			self._page = self._context.new_page()
			# CDP 模式下用较长超时 + commit 级等待（避免 networkidle 卡住）
			try:
				self._page.goto(HOME_URL, wait_until="commit", timeout=_NAV_TIMEOUT_MS)
			except Exception:
				pass  # 即使导航超时，页面 JS 环境已可用
			self._started = True
			self._is_cdp = True
			reuse_label = "复用用户 context" if not self._own_context else "新建 context"
			self._log(f"[boss] CDP 连接成功 ({url})，{reuse_label}")
			return True
		except Exception:
			if self._browser:
				try:
					self._browser.close()
				except Exception:
					pass
				self._browser = None
			return False

	@staticmethod
	def _fetch_ws_url(http_url: str, timeout: float = _CDP_PROBE_TIMEOUT) -> str | None:
		"""Fetch WebSocket debugger URL from Chrome's /json/version endpoint."""
		import httpx

		try:
			resp = httpx.get(f"{http_url}/json/version", timeout=timeout)
			payload = resp.json()
			if not isinstance(payload, dict):
				return None
			return cast("str | None", payload.get("webSocketDebuggerUrl"))
		except (httpx.HTTPError, ValueError, KeyError):
			return None

	@staticmethod
	def _read_devtools_active_port() -> str | None:
		"""Read Chrome's DevToolsActivePort file to get WS endpoint."""
		for user_data_dir in _CHROME_USER_DATA_CANDIDATES:
			port_file = user_data_dir / "DevToolsActivePort"
			if port_file.exists():
				try:
					lines = port_file.read_text().strip().splitlines()
					if len(lines) >= 2:
						port = lines[0].strip()
						ws_path = lines[1].strip()
						return f"ws://127.0.0.1:{port}{ws_path}"
				except Exception:
					continue
		return None

	def _start_headless(self) -> None:
		"""Fallback: launch headless patchright Chromium."""
		self._browser = self._pw.chromium.launch(**_chromium_launch_options(headless=True))
		self._context = self._browser.new_context(
			user_agent=self._user_agent,
			viewport={"width": 1280, "height": 800},
			locale="zh-CN",
			timezone_id="Asia/Shanghai",
		)
		self._own_context = True
		self._context.add_cookies(
			[
				{"name": name, "value": value, "domain": ".zhipin.com", "path": "/"}
				for name, value in self._cookies.items()
			]
		)
		self._page = self._context.new_page()
		self._page.goto(HOME_URL, wait_until="domcontentloaded", timeout=_NAV_TIMEOUT_MS)
		try:
			self._page.wait_for_load_state("networkidle", timeout=_HEADLESS_NETWORKIDLE_GRACE_MS)
		except Exception as e:
			# zhipin 首页常驻请求较多，headless 模式下不一定能进入 networkidle；
			# 页面 JS 环境已可用时，继续直接发起 fetch 请求更稳。
			self._log(f"[boss] headless 首页未进入 networkidle（{e}），继续直接发起请求")
		self._started = True
		self._is_cdp = False
		self._log(
			"[boss] CDP 不可用（提示：需以 --remote-debugging-port=9222 启动 Chrome），降级到 headless patchright"
		)

	# ── Core request via browser fetch() ─────────────────────────────

	def request(
		self, method: str, url: str, *, params: dict[str, Any] | None = None, data: dict[str, Any] | None = None
	) -> dict[str, Any]:
		self._ensure_started()
		self._throttle.wait()

		referer = endpoints.REFERER_MAP.get(url, f"{endpoints.BASE_URL}/")

		# Bridge 模式：通过扩展 fetch
		if self._is_bridge and self._bridge_client:
			import urllib.parse

			full_url = url
			if params:
				full_url = f"{url}?{urllib.parse.urlencode(params)}"
			result = self._bridge_client.fetch_json(
				full_url,
				method=method,
				data=data,
				referer=referer,
			)
			self._throttle.mark()
			return cast("dict[str, Any]", result)

		# Playwright 模式（CDP 或 headless）
		fetch_script = """
			async ({method, url, params, data, referer, timeoutMs}) => {
				const controller = new AbortController();
				const timer = setTimeout(() => controller.abort(), timeoutMs);
				try {
					let fetchUrl = url;
					if (params && Object.keys(params).length > 0) {
						const sp = new URLSearchParams();
						for (const [k, v] of Object.entries(params)) {
							if (v !== null && v !== undefined) sp.append(k, String(v));
						}
						fetchUrl = url + '?' + sp.toString();
					}

					const options = {
						method: method,
						credentials: 'include',
						signal: controller.signal,
						headers: {
							'Accept': 'application/json, text/plain, */*',
							'Referer': referer,
							'X-Requested-With': 'XMLHttpRequest',
						},
					};

					if (method === 'POST' && data) {
						options.headers['Content-Type'] = 'application/x-www-form-urlencoded';
						const formData = new URLSearchParams();
						for (const [k, v] of Object.entries(data)) {
							formData.append(k, String(v));
						}
						options.body = formData.toString();
					}

					const resp = await fetch(fetchUrl, options);
					return await resp.json();
				} catch (e) {
					return {code: -1, message: e.message, zpData: {}};
				} finally {
					clearTimeout(timer);
				}
			}
		"""
		evaluate_arg = {
			"method": method,
			"url": url,
			"params": params or {},
			"data": data,
			"referer": referer,
			"timeoutMs": _FETCH_TIMEOUT_MS,
		}
		result: dict[str, Any] | None = None
		last_navigation_error: Exception | None = None
		for attempt in range(2):
			try:
				result = cast("dict[str, Any]", self._page.evaluate(fetch_script, evaluate_arg))
				break
			except Exception as exc:
				message = str(exc)
				if "Execution context was destroyed" not in message and "most likely because of a navigation" not in message:
					raise
				last_navigation_error = exc
				if attempt == 1:
					break
				try:
					self._page.wait_for_load_state("domcontentloaded", timeout=3000)
				except Exception:
					time.sleep(0.3)
		if result is None:
			raise last_navigation_error or RuntimeError("browser fetch evaluation failed")

		self._throttle.mark()
		return result

	# ── Arbitrary JS evaluation (CDP-only, raw websocket) ────────────

	def evaluate_js(self, script: str, arg: Any = None) -> Any:
		"""Run JS in the user's recruiter chat tab via raw CDP websocket.

		Required for recruiter send_message (issue #217): we reach into the
		招聘者 chat page's Vue 2 instance to call geek-list.geekClick() +
		editor.sendText(). The normal BrowserSession.request fetch path can't
		do that — it runs JS in a blank tab BrowserSession owns, not in the
		user's recruiter tab.

		Why raw CDP instead of patchright: attaching patchright to another
		tab we didn't create via new_page() triggers 'Frame was detached'
		errors when that page navigates or re-renders (Vue SFC rebuilds
		frame tree). Raw CDP is a stateless RPC — we just send
		Runtime.evaluate and read the result, no session book-keeping.

		Intentionally does NOT call _ensure_started(): patchright's
		connect_over_cdp enumerates every tab's frame tree on attach, which
		can race with Vue re-renders on the recruiter page and crash the
		Node driver before we even get to our evaluate call. evaluate_js
		only needs the CDP HTTP endpoint reachable — not patchright.

		Only works in CDP mode (user has chrome://<devtools port>/json
		reachable and the recruiter chat tab open). Bridge/headless modes
		have no access to the user's Vue runtime.
		"""
		if self._is_bridge:
			raise RuntimeError("evaluate_js requires CDP mode (bridge mode has no access to user Chrome)")
		cdp_url = self._cdp_url or CDP_DEFAULT_URL
		return _cdp_evaluate_in_chat_tab(cdp_url, script, arg)

	def evaluate_js_with_chat_events(self, script: str, arg: Any = None, *, listen_ms: int = 3000) -> dict[str, Any]:
		"""Run JS in the recruiter chat tab and collect short-lived chat WS events.

		Used by recruiter send_message verification to distinguish a real chat send
		from UI-only draft mutation or suggestion traffic.
		"""
		if self._is_bridge:
			raise RuntimeError(
				"evaluate_js_with_chat_events requires CDP mode (bridge mode has no access to user Chrome)"
			)
		cdp_url = self._cdp_url or CDP_DEFAULT_URL
		return _cdp_evaluate_with_chat_events_in_chat_tab(cdp_url, script, arg, listen_ms=listen_ms)

	# ── Lifecycle ────────────────────────────────────────────────────

	@property
	def is_cdp(self) -> bool:
		"""Whether this session is using CDP connection to user's Chrome."""
		return self._is_cdp

	def close(self) -> None:
		if self._is_bridge and self._bridge_client:
			try:
				self._bridge_client.close_window()
			except Exception:
				pass
			self._bridge_client = None
			self._started = False
			return

		if self._is_cdp:
			# CDP 模式：关闭我们创建的 page 和 context，不关闭用户浏览器
			if self._page:
				try:
					self._page.close()
				except Exception:
					pass
			if self._own_context and self._context:
				try:
					self._context.close()
				except Exception:
					pass
		else:
			# Headless 模式：关闭整个浏览器实例
			if self._browser:
				try:
					self._browser.close()
				except Exception:
					pass
		if self._pw:
			try:
				self._pw.stop()
			except Exception:
				pass
		self._started = False

	def __enter__(self) -> "BrowserSession":
		return self

	def __exit__(
		self,
		exc_type: type[BaseException] | None,
		exc_val: BaseException | None,
		exc_tb: TracebackType | None,
	) -> None:
		self.close()


# ─── Raw CDP helper for evaluate_js ──────────────────────────────────────


def _pick_chat_target_ws(cdp_http_url: str) -> str:
	import json as _json
	import urllib.request

	list_url = cdp_http_url.rstrip("/") + "/json"
	try:
		with urllib.request.urlopen(list_url, timeout=3) as resp:
			tabs = _json.load(resp)
	except Exception as exc:
		raise RuntimeError(f"cannot reach CDP at {list_url}: {exc}") from exc

	for t in tabs:
		if t.get("type") == "page" and "/web/chat/index" in t.get("url", ""):
			target_ws = t.get("webSocketDebuggerUrl")
			if target_ws:
				return cast("str", target_ws)
	raise RecruiterChatTabRequired()


def _pick_zhipin_target_ws(cdp_http_url: str) -> str:
	import json as _json
	import urllib.request

	list_url = cdp_http_url.rstrip("/") + "/json"
	try:
		with urllib.request.urlopen(list_url, timeout=3) as resp:
			tabs = _json.load(resp)
	except Exception as exc:
		raise RuntimeError(f"cannot reach CDP at {list_url}: {exc}") from exc

	for t in tabs:
		if (
			t.get("type") == "page"
			and "zhipin.com" in t.get("url", "")
			and t.get("webSocketDebuggerUrl")
		):
			return cast("str", t["webSocketDebuggerUrl"])
	raise RuntimeError("no zhipin.com page found in CDP browser")


def _build_eval_expression(script: str, arg: Any) -> str:
	import json as _json

	if arg is not None:
		return f"({script})({_json.dumps(arg, ensure_ascii=False)})"
	return script


def raw_cdp_fetch_json(
	cdp_http_url: str,
	method: str,
	url: str,
	*,
	params: dict[str, Any] | None = None,
	data: dict[str, Any] | None = None,
	referer: str = HOME_URL,
	timeout_ms: int = _FETCH_TIMEOUT_MS,
) -> dict[str, Any]:
	"""Run a same-origin fetch in an existing zhipin.com tab via raw CDP.

	This avoids patchright's connect_over_cdp context enumeration, which can
	hang when the user's browser has many dynamic BOSS tabs open.
	"""
	import json as _json

	import websockets.sync.client as _ws_client

	target_ws = _pick_zhipin_target_ws(cdp_http_url)
	script = """
async (arg) => {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), arg.timeoutMs);
  try {
    let fetchUrl = arg.url;
    if (arg.params && Object.keys(arg.params).length > 0) {
      const sp = new URLSearchParams();
      for (const [k, v] of Object.entries(arg.params)) {
        if (v !== null && v !== undefined) sp.append(k, String(v));
      }
      fetchUrl = arg.url + "?" + sp.toString();
    }
    const options = {
      method: arg.method,
      credentials: "include",
      signal: controller.signal,
      headers: {
        Accept: "application/json, text/plain, */*",
        Referer: arg.referer,
        "X-Requested-With": "XMLHttpRequest",
      },
    };
    if (arg.method === "POST" && arg.data) {
      options.headers["Content-Type"] = "application/x-www-form-urlencoded";
      const formData = new URLSearchParams();
      for (const [k, v] of Object.entries(arg.data)) {
        formData.append(k, String(v));
      }
      options.body = formData.toString();
    }
    const resp = await fetch(fetchUrl, options);
    return await resp.json();
  } catch (e) {
    return { code: -1, message: e.name + ": " + e.message, zpData: {} };
  } finally {
    clearTimeout(timer);
  }
}
"""
	expression = _build_eval_expression(
		script,
		{
			"method": method,
			"url": url,
			"params": params or {},
			"data": data,
			"referer": referer,
			"timeoutMs": timeout_ms,
		},
	)
	with _ws_client.connect(target_ws, max_size=8 * 1024 * 1024, open_timeout=3) as ws:
		ws.send(
			_json.dumps(
				{
					"id": 1,
					"method": "Runtime.evaluate",
					"params": {
						"expression": expression,
						"returnByValue": True,
						"awaitPromise": True,
					},
				}
			)
		)
		deadline = time.time() + max(5.0, (timeout_ms / 1000.0) + 3.0)
		while time.time() < deadline:
			raw = ws.recv(timeout=max(0.1, deadline - time.time()))
			msg = _json.loads(raw)
			if msg.get("id") != 1:
				continue
			err = msg.get("error")
			if err:
				raise RuntimeError(f"CDP Runtime.evaluate error: {err}")
			result = msg.get("result", {}).get("result", {})
			if "value" in result:
				value = result["value"]
				return value if isinstance(value, dict) else {"code": -1, "message": "CDP fetch returned non-object", "zpData": {}}
			exc_details = msg.get("result", {}).get("exceptionDetails")
			if exc_details:
				raise RuntimeError(
					f"JS exception: {exc_details.get('text')} - "
					f"{exc_details.get('exception', {}).get('description', '')[:300]}"
				)
			return {"code": -1, "message": "CDP fetch returned no value", "zpData": {}}
		raise RuntimeError("CDP Runtime.evaluate timed out")


def _carve_utf8_bits(bs: bytes) -> list[str]:
	out: list[str] = []
	i = 0
	while i < len(bs):
		for length in range(min(len(bs) - i, 240), 4, -1):
			try:
				text = bs[i : i + length].decode("utf-8")
			except UnicodeDecodeError:
				continue
			if len(text) >= 5 and all(ch.isprintable() or ch in "\n\r\t" for ch in text):
				out.append(text)
				i += length
				break
		else:
			i += 1
	return out


def _cdp_evaluate_in_chat_tab(cdp_http_url: str, script: str, arg: Any) -> Any:
	"""Send Runtime.evaluate to the BOSS recruiter chat tab via raw CDP.

	Bypasses patchright entirely — avoids 'Frame was detached' errors when
	the Vue page re-renders during our call. Wraps the caller's script as
	`(fnSrc)(arg)` when arg is provided, so the script can be a JS expression
	that evaluates to a function of one argument (mirrors patchright's
	`page.evaluate(script, arg)` contract used by the PoC).
	"""
	import json as _json

	import websockets.sync.client as _ws_client

	target_ws = _pick_chat_target_ws(cdp_http_url)
	expression = _build_eval_expression(script, arg)

	with _ws_client.connect(target_ws, max_size=8 * 1024 * 1024) as ws:
		ws.send(
			_json.dumps(
				{
					"id": 1,
					"method": "Runtime.evaluate",
					"params": {
						"expression": expression,
						"returnByValue": True,
						"awaitPromise": True,
					},
				}
			)
		)
		deadline = time.time() + 30.0
		while time.time() < deadline:
			raw = ws.recv(timeout=max(0.1, deadline - time.time()))
			msg = _json.loads(raw)
			if msg.get("id") != 1:
				continue
			err = msg.get("error")
			if err:
				raise RuntimeError(f"CDP Runtime.evaluate error: {err}")
			result = msg.get("result", {}).get("result", {})
			if "value" in result:
				return result["value"]
			# Exception in JS side
			exc_details = msg.get("result", {}).get("exceptionDetails")
			if exc_details:
				raise RuntimeError(
					f"JS exception: {exc_details.get('text')} — {exc_details.get('exception', {}).get('description', '')[:300]}"
				)
			return result
		raise RuntimeError("CDP Runtime.evaluate timed out after 30s")


def _cdp_evaluate_with_chat_events_in_chat_tab(
	cdp_http_url: str, script: str, arg: Any, *, listen_ms: int
) -> dict[str, Any]:
	import base64 as _base64
	import json as _json

	import websockets.sync.client as _ws_client

	target_ws = _pick_chat_target_ws(cdp_http_url)
	expression = _build_eval_expression(script, arg)

	with _ws_client.connect(target_ws, max_size=8 * 1024 * 1024) as ws:
		ws.send(_json.dumps({"id": 1, "method": "Network.enable"}))
		ws.send(
			_json.dumps(
				{
					"id": 2,
					"method": "Runtime.evaluate",
					"params": {
						"expression": expression,
						"returnByValue": True,
						"awaitPromise": True,
					},
				}
			)
		)

		events: list[dict[str, Any]] = []
		eval_value: Any = None
		eval_done = False
		deadline = time.time() + 30.0
		listen_deadline: float | None = None

		while True:
			now = time.time()
			if eval_done and listen_deadline is not None and now >= listen_deadline:
				return {"value": eval_value, "events": events}
			if now >= deadline:
				raise RuntimeError("CDP Runtime.evaluate timed out after 30s")

			timeout = 0.1 if eval_done and listen_deadline is not None else max(0.1, deadline - now)
			try:
				raw = ws.recv(timeout=timeout)
			except TimeoutError:
				continue

			msg = _json.loads(raw)
			msg_id = msg.get("id")
			if msg_id == 2:
				err = msg.get("error")
				if err:
					raise RuntimeError(f"CDP Runtime.evaluate error: {err}")
				result = msg.get("result", {}).get("result", {})
				exc_details = msg.get("result", {}).get("exceptionDetails")
				if exc_details:
					raise RuntimeError(
						f"JS exception: {exc_details.get('text')} — "
						f"{exc_details.get('exception', {}).get('description', '')[:300]}"
					)
				eval_value = result.get("value", result)
				eval_done = True
				listen_deadline = time.time() + (listen_ms / 1000.0)
				continue

			method = msg.get("method")
			if method not in ("Network.webSocketFrameSent", "Network.webSocketFrameReceived"):
				continue
			frame = msg.get("params", {}).get("response", {})
			if frame.get("opcode") not in (1, 2):
				continue

			payload_data = frame.get("payloadData", "")
			try:
				bs = _base64.b64decode(payload_data, validate=False)
			except Exception:
				bs = payload_data.encode("utf-8", errors="ignore")
			if len(bs) < 30:
				continue

			events.append(
				{
					"ts": time.time(),
					"kind": "ws_send" if method.endswith("Sent") else "ws_recv",
					"bytes": len(bs),
					"utf8_bits": _carve_utf8_bits(bs)[:10],
				}
			)
